			progresDialog.setOwnerActivity(UserDictionaryEditorActivity.this);

			progresDialog.show();
		}

		protected void onPostExecute(String[] result) {
			progresDialog.dismiss();
			applyResults(result);
		}

		protected abstract void applyResults(String[] result);
	}

